export const resolveLogo = (
  input: Record<string, unknown>,
): string | undefined => {
  const key =
    `inverse:${input.inverse ?? "null"}|` +
    `logoLanguage:${input.logoLanguage ?? "null"}|` +
    `symbol:${input.symbol ?? "null"}|` +
    `type:${input.type ?? "null"}`;

  return LOGO_MAP[key] ?? undefined;
};
